import{_ as e,o as a,c as n,a2 as s}from"./chunks/framework.D36jym0Z.js";const g=JSON.parse('{"title":"TokenPilot Overview","description":"","frontmatter":{},"headers":[],"relativePath":"plugin-catalog/tokenpilot/overview.md","filePath":"plugin-catalog/tokenpilot/overview.md","lastUpdated":1784629191000}'),l={name:"plugin-catalog/tokenpilot/overview.md"};function o(i,t,r,p,d,h){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="tokenpilot-overview" tabindex="-1">TokenPilot Overview <a class="header-anchor" href="#tokenpilot-overview" aria-label="Permalink to &quot;TokenPilot Overview&quot;">​</a></h1><p>TokenPilot is the first official LightMem2 plugin. It is a <strong>cache-aware context runtime</strong> that reduces token usage and cost in long-running agent sessions.</p><h2 id="what-tokenpilot-does" tabindex="-1">What TokenPilot Does <a class="header-anchor" href="#what-tokenpilot-does" aria-label="Permalink to &quot;What TokenPilot Does&quot;">​</a></h2><p>Agent sessions grow. Every turn adds more messages, more tool outputs, more context. The model sees all of it, and you pay for all of it. Much of that context is repetitive — identical prefixes sent every turn, bloated tool outputs, stale history.</p><p>TokenPilot addresses this with three techniques:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                 TokenPilot Pipeline                   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1. Stable Prefix                                    │</span></span>
<span class="line"><span>│     Rewrites context into cache-stable form           │</span></span>
<span class="line"><span>│     → Higher cache hit rate                          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2. Context Reduction                                │</span></span>
<span class="line"><span>│     Trims oversized tool output before it pollutes   │</span></span>
<span class="line"><span>│     → Leaner context per turn                        │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3. Context Eviction                                 │</span></span>
<span class="line"><span>│     Limits how much old context is carried forward   │</span></span>
<span class="line"><span>│     → Sessions don&#39;t grow unbounded                  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="key-results" tabindex="-1">Key Results <a class="header-anchor" href="#key-results" aria-label="Permalink to &quot;Key Results&quot;">​</a></h2><p>From the <a href="https://arxiv.org/abs/2606.17016" target="_blank" rel="noreferrer">TokenPilot paper</a>, evaluated on PinchBench and Claw-Eval benchmarks (continuous mode):</p><table tabindex="0"><thead><tr><th style="text-align:left;">Metric</th><th style="text-align:right;">PinchBench</th><th style="text-align:right;">Claw-Eval</th></tr></thead><tbody><tr><td style="text-align:left;">Input token reduction</td><td style="text-align:right;"><strong>67.4%</strong></td><td style="text-align:right;"><strong>95.7%</strong></td></tr><tr><td style="text-align:left;">Cost reduction</td><td style="text-align:right;"><strong>61.5%</strong></td><td style="text-align:right;"><strong>87.0%</strong></td></tr><tr><td style="text-align:left;">Cache read (M tokens)</td><td style="text-align:right;">8.55 vs. 25.02 (Vanilla)</td><td style="text-align:right;">21.43 vs. 709.85 (Vanilla)</td></tr></tbody></table><p>See <a href="/LightMem2/plugin-catalog/tokenpilot/benchmarks">Benchmarks</a> for full results.</p><h2 id="supported-hosts" tabindex="-1">Supported Hosts <a class="header-anchor" href="#supported-hosts" aria-label="Permalink to &quot;Supported Hosts&quot;">​</a></h2><p>TokenPilot works on three agent hosts, each with a different integration style:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Host</th><th style="text-align:left;">Integration</th><th style="text-align:left;">Page</th></tr></thead><tbody><tr><td style="text-align:left;">OpenClaw</td><td style="text-align:left;">Native plugin slot</td><td style="text-align:left;"><a href="/LightMem2/hosts/openclaw">OpenClaw</a></td></tr><tr><td style="text-align:left;">Codex CLI</td><td style="text-align:left;">Local proxy + hooks</td><td style="text-align:left;"><a href="/LightMem2/hosts/codex">Codex</a></td></tr><tr><td style="text-align:left;">Claude Code</td><td style="text-align:left;">Local gateway + MCP</td><td style="text-align:left;"><a href="/LightMem2/hosts/claude-code">Claude Code</a></td></tr></tbody></table><p>Features are consistent across hosts. Differences are documented on each host page.</p><h2 id="quick-tour" tabindex="-1">Quick Tour <a class="header-anchor" href="#quick-tour" aria-label="Permalink to &quot;Quick Tour&quot;">​</a></h2><ul><li><a href="/LightMem2/plugin-catalog/tokenpilot/installation">Installation</a> — get TokenPilot running</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/configuration">Configuration</a> — settings and defaults</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/runtime-modes">Runtime Modes</a> — conservative, normal, aggressive</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/benchmarks">Benchmarks</a> — evaluation results</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/troubleshooting">Troubleshooting</a> — common problems and fixes</li></ul>`,16)])])}const u=e(l,[["render",o]]);export{g as __pageData,u as default};
